package com.schwab.urlShortener.ratelimit;

public class RateLimitExceededException extends RuntimeException {
    private final String clientIp;
    private final int limit;
    private final long windowSeconds;

    public RateLimitExceededException(String clientIp, int limit, long windowSeconds) {
        super(String.format("Rate limit exceeded for IP %s: %d requests per %d seconds", 
              clientIp, limit, windowSeconds));
        this.clientIp = clientIp;
        this.limit = limit;
        this.windowSeconds = windowSeconds;
    }

    public String getClientIp() {
        return clientIp;
    }

    public int getLimit() {
        return limit;
    }

    public long getWindowSeconds() {
        return windowSeconds;
    }
}

package com.schwab.urlShortener.ratelimit;

import jakarta.servlet.http.HttpServletRequest;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

import java.time.Clock;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

@Component
public class IpRateLimiter {

    private final Clock clock;
    private final int maxRequestsPerWindow;
    private final long windowSeconds;

    private final Map<String, RequestWindow> requestCounts = new ConcurrentHashMap<>();

    public IpRateLimiter(
            Clock clock,
            @Value("${ratelimit.max-requests:100}") int maxRequestsPerWindow,
            @Value("${ratelimit.window-seconds:60}") long windowSeconds) {
        this.clock = clock;
        this.maxRequestsPerWindow = maxRequestsPerWindow;
        this.windowSeconds = windowSeconds;
    }

    public void checkAndIncrement(HttpServletRequest request) {
        String clientIp = extractClientIp(request);
        long currentTime = clock.instant().getEpochSecond();
        long currentWindow = currentTime / windowSeconds;

        RequestWindow window = requestCounts.compute(clientIp, (ip, existing) -> {
            if (existing == null || existing.windowId != currentWindow) {
                return new RequestWindow(currentWindow, new AtomicInteger(1));
            }
            existing.count.incrementAndGet();
            return existing;
        });

        if (window.count.get() > maxRequestsPerWindow) {
            throw new RateLimitExceededException(clientIp, maxRequestsPerWindow, windowSeconds);
        }

        // Clean up old windows periodically (simple cleanup on every 100th request)
        if (window.count.get() % 100 == 0) {
            requestCounts.entrySet().removeIf(entry -> 
                entry.getValue().windowId < currentWindow - 1
            );
        }
    }

    private String extractClientIp(HttpServletRequest request) {
        String forwardedFor = request.getHeader("X-Forwarded-For");
        if (forwardedFor != null && !forwardedFor.isEmpty()) {
            return forwardedFor.split(",")[0].trim();
        }

        String realIp = request.getHeader("X-Real-IP");
        if (realIp != null && !realIp.isEmpty()) {
            return realIp;
        }

        return request.getRemoteAddr();
    }

    private static class RequestWindow {
        final long windowId;
        final AtomicInteger count;

        RequestWindow(long windowId, AtomicInteger count) {
            this.windowId = windowId;
            this.count = count;
        }
    }
}

package com.schwab.urlShortener.api;

import com.schwab.urlShortener.domain.InvalidUrlException;
import com.schwab.urlShortener.domain.ShortLinkNotFoundException;
import com.schwab.urlShortener.ratelimit.RateLimitExceededException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ProblemDetail;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.ResponseStatus;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.net.URI;
import java.time.Instant;
import java.util.stream.Collectors;

/**
 * Global exception handler that converts domain exceptions into RFC 9457 ProblemDetail responses.
 * <p>
 * This handler ensures consistent error response format across all API endpoints.
 * It logs client errors (4xx) at DEBUG level since they represent normal traffic patterns,
 * not application problems requiring investigation.
 * </p>
 */
@RestControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger log = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(ShortLinkNotFoundException.class)
    @ResponseStatus(HttpStatus.NOT_FOUND)
    public ProblemDetail handleShortLinkNotFound(ShortLinkNotFoundException ex) {
        log.debug("Short link not found: {}", ex.getMessage());
        return problem(
                HttpStatus.NOT_FOUND,
                "Short Link Not Found",
                ex.getMessage(),
                "short-link-not-found"
        );
    }

    @ExceptionHandler(InvalidUrlException.class)
    @ResponseStatus(HttpStatus.BAD_REQUEST)
    public ProblemDetail handleInvalidUrl(InvalidUrlException ex) {
        log.debug("Invalid URL submitted: {}", ex.getMessage());
        return problem(
                HttpStatus.BAD_REQUEST,
                "Invalid URL",
                ex.getMessage(),
                "invalid-url"
        );
    }

    @ExceptionHandler(RateLimitExceededException.class)
    @ResponseStatus(HttpStatus.TOO_MANY_REQUESTS)
    public ProblemDetail handleRateLimitExceeded(RateLimitExceededException ex) {
        log.debug("Rate limit exceeded for IP {}: {} requests per {} seconds", 
                  ex.getClientIp(), ex.getLimit(), ex.getWindowSeconds());
        return problem(
                HttpStatus.TOO_MANY_REQUESTS,
                "Rate Limit Exceeded",
                String.format("Too many requests. Limit: %d requests per %d seconds.", 
                              ex.getLimit(), ex.getWindowSeconds()),
                "rate-limit-exceeded"
        );
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    @ResponseStatus(HttpStatus.BAD_REQUEST)
    public ProblemDetail handleValidationErrors(MethodArgumentNotValidException ex) {
        String errors = ex.getBindingResult()
                .getFieldErrors()
                .stream()
                .map(error -> error.getField() + ": " + error.getDefaultMessage())
                .collect(Collectors.joining(", "));

        log.debug("Validation failed: {}", errors);
        return problem(
                HttpStatus.BAD_REQUEST,
                "Validation Failed",
                errors,
                "validation-error"
        );
    }

    @ExceptionHandler(Exception.class)
    @ResponseStatus(HttpStatus.INTERNAL_SERVER_ERROR)
    public ProblemDetail handleGenericException(Exception ex) {
        log.error("Unexpected error processing request", ex);
        return problem(
                HttpStatus.INTERNAL_SERVER_ERROR,
                "Internal Server Error",
                "An unexpected error occurred processing your request",
                "internal-error"
        );
    }

    private ProblemDetail problem(HttpStatus status, String title, String detail, String type) {
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(status, detail);
        problemDetail.setTitle(title);
        problemDetail.setType(URI.create("https://schwab.com/problems/" + type));
        problemDetail.setProperty("timestamp", Instant.now());
        return problemDetail;
    }
}

package com.schwab.urlShortener.ratelimit;

import jakarta.servlet.http.HttpServletRequest;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.time.Clock;
import java.time.Instant;
import java.time.ZoneId;

import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.assertj.core.api.Assertions.assertThatCode;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
class IpRateLimiterTest {

    @Mock
    private HttpServletRequest request;

    private FakeableClock clock;
    private IpRateLimiter rateLimiter;

    @BeforeEach
    void setUp() {
        clock = new FakeableClock();
        rateLimiter = new IpRateLimiter(clock, 5, 60);
    }

    @Test
    void allowsRequestsWithinLimit() {
        when(request.getRemoteAddr()).thenReturn("192.168.1.100");

        // Should allow 5 requests without throwing
        assertThatCode(() -> {
            for (int i = 0; i < 5; i++) {
                rateLimiter.checkAndIncrement(request);
            }
        }).doesNotThrowAnyException();
    }

    @Test
    void rejectsRequestsExceedingLimit() {
        when(request.getRemoteAddr()).thenReturn("192.168.1.100");

        // First 5 requests succeed
        for (int i = 0; i < 5; i++) {
            rateLimiter.checkAndIncrement(request);
        }

        // 6th request should fail
        assertThatThrownBy(() -> rateLimiter.checkAndIncrement(request))
                .isInstanceOf(RateLimitExceededException.class)
                .hasMessageContaining("192.168.1.100")
                .hasMessageContaining("5 requests per 60 seconds");
    }

    @Test
    void resetsCounterInNewTimeWindow() {
        when(request.getRemoteAddr()).thenReturn("192.168.1.100");

        // Use up the limit in first window
        for (int i = 0; i < 5; i++) {
            rateLimiter.checkAndIncrement(request);
        }

        // Move to next window (60 seconds later)
        clock.advanceSeconds(60);

        // Should allow 5 more requests in the new window
        assertThatCode(() -> {
            for (int i = 0; i < 5; i++) {
                rateLimiter.checkAndIncrement(request);
            }
        }).doesNotThrowAnyException();
    }

    @Test
    void tracksMultipleIpsSeparately() {
        HttpServletRequest request1 = request;
        when(request1.getRemoteAddr()).thenReturn("192.168.1.100");

        HttpServletRequest request2 = org.mockito.Mockito.mock(HttpServletRequest.class);
        when(request2.getRemoteAddr()).thenReturn("192.168.1.101");

        // Exhaust limit for first IP
        for (int i = 0; i < 5; i++) {
            rateLimiter.checkAndIncrement(request1);
        }

        // Second IP should still be allowed
        assertThatCode(() -> rateLimiter.checkAndIncrement(request2))
                .doesNotThrowAnyException();
    }

    @Test
    void extractsIpFromXForwardedForHeader() {
        when(request.getHeader("X-Forwarded-For")).thenReturn("203.0.113.1, 198.51.100.1");
        when(request.getRemoteAddr()).thenReturn("192.168.1.1");

        // Use up limit
        for (int i = 0; i < 5; i++) {
            rateLimiter.checkAndIncrement(request);
        }

        // Should reject based on the forwarded IP (203.0.113.1)
        assertThatThrownBy(() -> rateLimiter.checkAndIncrement(request))
                .isInstanceOf(RateLimitExceededException.class)
                .hasMessageContaining("203.0.113.1");
    }

    @Test
    void extractsIpFromXRealIpHeader() {
        when(request.getHeader("X-Forwarded-For")).thenReturn(null);
        when(request.getHeader("X-Real-IP")).thenReturn("203.0.113.50");
        when(request.getRemoteAddr()).thenReturn("192.168.1.1");

        // Use up limit
        for (int i = 0; i < 5; i++) {
            rateLimiter.checkAndIncrement(request);
        }

        // Should reject based on X-Real-IP
        assertThatThrownBy(() -> rateLimiter.checkAndIncrement(request))
                .isInstanceOf(RateLimitExceededException.class)
                .hasMessageContaining("203.0.113.50");
    }

    @Test
    void fallsBackToRemoteAddrWhenNoProxyHeaders() {
        when(request.getHeader("X-Forwarded-For")).thenReturn(null);
        when(request.getHeader("X-Real-IP")).thenReturn(null);
        when(request.getRemoteAddr()).thenReturn("192.168.1.200");

        // Use up limit
        for (int i = 0; i < 5; i++) {
            rateLimiter.checkAndIncrement(request);
        }

        // Should reject based on remote address
        assertThatThrownBy(() -> rateLimiter.checkAndIncrement(request))
                .isInstanceOf(RateLimitExceededException.class)
                .hasMessageContaining("192.168.1.200");
    }

    @Test
    void handlesEmptyForwardedForHeader() {
        when(request.getHeader("X-Forwarded-For")).thenReturn("");
        when(request.getHeader("X-Real-IP")).thenReturn(null);
        when(request.getRemoteAddr()).thenReturn("192.168.1.99");

        rateLimiter.checkAndIncrement(request);

        // Should use remote address when header is empty
        for (int i = 0; i < 4; i++) {
            rateLimiter.checkAndIncrement(request);
        }

        assertThatThrownBy(() -> rateLimiter.checkAndIncrement(request))
                .isInstanceOf(RateLimitExceededException.class)
                .hasMessageContaining("192.168.1.99");
    }

    @Test
    void rejectsImmediatelyOnExceedingLimit() {
        when(request.getRemoteAddr()).thenReturn("10.0.0.1");

        // Make exactly the limit number of requests
        for (int i = 0; i < 5; i++) {
            rateLimiter.checkAndIncrement(request);
        }

        // Very next request (even 1ms later) should fail
        assertThatThrownBy(() -> rateLimiter.checkAndIncrement(request))
                .isInstanceOf(RateLimitExceededException.class);
    }

    @Test
    void includesCorrectLimitDetailsInException() {
        when(request.getRemoteAddr()).thenReturn("172.16.0.1");

        for (int i = 0; i < 5; i++) {
            rateLimiter.checkAndIncrement(request);
        }

        assertThatThrownBy(() -> rateLimiter.checkAndIncrement(request))
                .isInstanceOf(RateLimitExceededException.class)
                .satisfies(ex -> {
                    RateLimitExceededException rle = (RateLimitExceededException) ex;
                    org.assertj.core.api.Assertions.assertThat(rle.getClientIp()).isEqualTo("172.16.0.1");
                    org.assertj.core.api.Assertions.assertThat(rle.getLimit()).isEqualTo(5);
                    org.assertj.core.api.Assertions.assertThat(rle.getWindowSeconds()).isEqualTo(60);
                });
    }

    private static class FakeableClock extends Clock {
        private Instant current = Instant.parse("2024-01-01T12:00:00Z");

        @Override
        public ZoneId getZone() {
            return ZoneId.of("UTC");
        }

        @Override
        public Clock withZone(ZoneId zone) {
            return this;
        }

        @Override
        public Instant instant() {
            return current;
        }

        public void advanceSeconds(long seconds) {
            current = current.plusSeconds(seconds);
        }
    }
}

package com.schwab.urlShortener.api;

import com.schwab.urlShortener.domain.InvalidUrlException;
import com.schwab.urlShortener.domain.ShortLinkNotFoundException;
import com.schwab.urlShortener.ratelimit.RateLimitExceededException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.http.HttpStatus;
import org.springframework.http.ProblemDetail;
import org.springframework.validation.BindingResult;
import org.springframework.validation.FieldError;
import org.springframework.web.bind.MethodArgumentNotValidException;

import java.net.URI;
import java.time.Instant;
import java.util.List;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

class GlobalExceptionHandlerTest {

    private GlobalExceptionHandler handler;

    @BeforeEach
    void setUp() {
        handler = new GlobalExceptionHandler();
    }

    @Test
    void handlesRateLimitExceededWith429Status() {
        RateLimitExceededException ex = new RateLimitExceededException("192.168.1.100", 100, 60);

        ProblemDetail result = handler.handleRateLimitExceeded(ex);

        assertThat(result.getStatus()).isEqualTo(HttpStatus.TOO_MANY_REQUESTS.value());
        assertThat(result.getTitle()).isEqualTo("Rate Limit Exceeded");
        assertThat(result.getDetail())
                .contains("Too many requests")
                .contains("100 requests per 60 seconds");
        assertThat(result.getType()).isEqualTo(URI.create("https://schwab.com/problems/rate-limit-exceeded"));
        assertThat(result.getProperties()).containsKey("timestamp");
        assertThat(result.getProperties().get("timestamp")).isInstanceOf(Instant.class);
    }

    @Test
    void handlesShortLinkNotFoundWith404Status() {
        ShortLinkNotFoundException ex = new ShortLinkNotFoundException("abc123");

        ProblemDetail result = handler.handleShortLinkNotFound(ex);

        assertThat(result.getStatus()).isEqualTo(HttpStatus.NOT_FOUND.value());
        assertThat(result.getTitle()).isEqualTo("Short Link Not Found");
        assertThat(result.getDetail()).contains("abc123");
        assertThat(result.getType()).isEqualTo(URI.create("https://schwab.com/problems/short-link-not-found"));
    }

    @Test
    void handlesInvalidUrlWith400Status() {
        InvalidUrlException ex = new InvalidUrlException("not a valid URL");

        ProblemDetail result = handler.handleInvalidUrl(ex);

        assertThat(result.getStatus()).isEqualTo(HttpStatus.BAD_REQUEST.value());
        assertThat(result.getTitle()).isEqualTo("Invalid URL");
        assertThat(result.getDetail()).isEqualTo("not a valid URL");
        assertThat(result.getType()).isEqualTo(URI.create("https://schwab.com/problems/invalid-url"));
    }

    @Test
    void handlesValidationErrorsWith400Status() {
        BindingResult bindingResult = mock(BindingResult.class);
        FieldError error1 = new FieldError("object", "url", "must not be blank");
        FieldError error2 = new FieldError("object", "customAlias", "invalid format");
        when(bindingResult.getFieldErrors()).thenReturn(List.of(error1, error2));

        MethodArgumentNotValidException ex = new MethodArgumentNotValidException(null, bindingResult);

        ProblemDetail result = handler.handleValidationErrors(ex);

        assertThat(result.getStatus()).isEqualTo(HttpStatus.BAD_REQUEST.value());
        assertThat(result.getTitle()).isEqualTo("Validation Failed");
        assertThat(result.getDetail())
                .contains("url: must not be blank")
                .contains("customAlias: invalid format");
        assertThat(result.getType()).isEqualTo(URI.create("https://schwab.com/problems/validation-error"));
    }

    @Test
    void handlesGenericExceptionWith500Status() {
        Exception ex = new RuntimeException("Unexpected failure");

        ProblemDetail result = handler.handleGenericException(ex);

        assertThat(result.getStatus()).isEqualTo(HttpStatus.INTERNAL_SERVER_ERROR.value());
        assertThat(result.getTitle()).isEqualTo("Internal Server Error");
        assertThat(result.getDetail()).isEqualTo("An unexpected error occurred processing your request");
        assertThat(result.getType()).isEqualTo(URI.create("https://schwab.com/problems/internal-error"));
    }

    @Test
    void includesTimestampInAllResponses() {
        RateLimitExceededException ex = new RateLimitExceededException("1.2.3.4", 10, 30);
        Instant before = Instant.now();

        ProblemDetail result = handler.handleRateLimitExceeded(ex);

        Instant after = Instant.now();
        Instant timestamp = (Instant) result.getProperties().get("timestamp");
        assertThat(timestamp).isBetween(before, after);
    }

    @Test
    void rateLimitExceptionPreservesAllDetails() {
        String testIp = "203.0.113.42";
        int testLimit = 50;
        long testWindow = 120;

        RateLimitExceededException ex = new RateLimitExceededException(testIp, testLimit, testWindow);

        ProblemDetail result = handler.handleRateLimitExceeded(ex);

        assertThat(result.getDetail())
                .contains(String.valueOf(testLimit))
                .contains(String.valueOf(testWindow));
    }
}
